from abc import ABC, abstractmethod

class AbstractClassName(ABC):
    @abstractmethod
    def method_name(self, param1, param2):
        """文档字符串描述方法"""
        pass

class ConcreteClass(AbstractClassName):
    def method_name(self, param1, param2):
        # 实现具体逻辑
        return param1 + param2
